// runOnceForEachItem: $json = Extract Paper Text HTTP response
const paper = $item(0).$node['Parse Papers'].json;
const paperUrl = paper.url || 'n/a';
const text = String($json.body || $json.data || $json.content || '').slice(0, 12000);

if (!text || text.length < 100) {
  return { json: { ...paper, ok: false, error_type: 'fetch_failed', error_message: 'Content too short or empty' } };
}

const payload = {
  model: 'solar-pro2',
  temperature: 0.2,
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'paper_summary',
      schema: {
        type: 'object',
        properties: {
          title: { type: 'string' },
          one_line: { type: 'string' },
          problem: { type: 'string' },
          method: { type: 'string' },
          results: { type: 'string' },
          limitations: { type: 'string' },
          tags: { type: 'array', items: { type: 'string' } },
          action_items: { type: 'array', items: { type: 'string' } }
        },
        required: ['title','one_line','problem','method','results','limitations','tags','action_items'],
        additionalProperties: false
      }
    }
  },
  messages: [
    { role: 'system', content: '너는 논문 리뷰 어시스턴트다. ko로만 답해라. 과장 금지. 수치/조건은 최대한 보존하라.' },
    { role: 'user', content: '다음 논문을 분석해 구조화 요약 JSON으로 만들어줘.\nURL: ' + paperUrl + '\n\n본문:\n' + text }
  ]
};

return { json: { ...paper, upstage_payload: payload } };

// runOnceForEachItem: $json = Upstage Summarize HTTP response
const paper = $item(0).$node['Build Summary Payload'].json || {};
const base = {
  paper_id: paper.paper_id || '',
  title: paper.title || '',
  url: paper.url || '',
  upvotes: paper.upvotes || 0,
  date: paper.date || ''
};

if ($json.error || (!$json.choices && !$json.body?.choices)) {
  return { json: { ...base, ok: false, error_type: 'upstage_error', error_message: $json.error?.message || $json.message || 'Unknown' } };
}

const choices = $json.choices || $json.body?.choices || [];
const content = choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch { parsed = { raw: content }; }
return { json: { ...base, ok: true, summary: parsed } };

const all = $input.all().map(i => i.json);
const date = all[0]?.date || 'unknown';
const ok = all.filter(x => x.ok !== false);
const failed = all.filter(x => x.ok === false);

let html = `<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;max-width:680px;margin:0 auto;padding:24px;">`;
html += `<h1 style="font-size:22px;color:#1a1a1a;">📄 Daily Paper Summary — ${date}</h1>`;
html += `<p style="color:#6b7280;font-size:14px;">Upstage Solar가 요약한 인기 논문 ${ok.length}편</p>`;
html += `<hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">`;

for (const item of ok) {
  const s = item.summary || {};
  html += `<div style="margin-bottom:28px;">`;
  html += `<h2 style="font-size:16px;margin:0 0 6px;"><a href="${item.url}" style="color:#6c2bd9;text-decoration:none;">${s.title || item.title}</a></h2>`;
  html += `<p style="color:#6b7280;font-size:12px;margin:0 0 8px;">⬆️ ${item.upvotes} · ${(s.tags||[]).join(', ')}</p>`;
  html += `<p style="font-size:14px;color:#374151;margin:0 0 8px;"><strong>한 줄:</strong> ${s.one_line || '-'}</p>`;
  html += `<table style="font-size:13px;color:#4b5563;border-collapse:collapse;width:100%;">`;
  html += `<tr><td style="padding:3px 8px 3px 0;font-weight:600;vertical-align:top;">문제</td><td>${s.problem||'-'}</td></tr>`;
  html += `<tr><td style="padding:3px 8px 3px 0;font-weight:600;vertical-align:top;">방법</td><td>${s.method||'-'}</td></tr>`;
  html += `<tr><td style="padding:3px 8px 3px 0;font-weight:600;vertical-align:top;">결과</td><td>${s.results||'-'}</td></tr>`;
  html += `<tr><td style="padding:3px 8px 3px 0;font-weight:600;vertical-align:top;">한계</td><td>${s.limitations||'-'}</td></tr>`;
  html += `</table>`;
  if (s.action_items?.length) html += `<p style="font-size:12px;color:#059669;margin:8px 0 0;">💡 ${s.action_items.join(' · ')}</p>`;
  html += `</div>`;
}

if (failed.length) html += `<p style="color:#ef4444;font-size:13px;">⚠️ ${failed.length}편 요약 실패</p>`;
html += `<hr style="border:none;border-top:1px solid #e5e7eb;margin:20px 0;">`;
html += `<p style="color:#9ca3af;font-size:12px;">Powered by <a href="https://www.upstage.ai" style="color:#6c2bd9;">Upstage Solar</a> · <a href="https://huggingface.co/papers" style="color:#6c2bd9;">HF Daily Papers</a></p></div>`;

return [{ json: { date, subject: `📄 Daily Paper Summary — ${date} (${ok.length}편)`, html, count: all.length, success: ok.length, failed: failed.length } }];

// n8n HTTP Request auto-splits JSON arrays into separate items
// So each item here is a single paper object from HF API
const allItems = $input.all().map(i => i.json);
const dateStr = new Date(Date.now() - 86400000).toISOString().slice(0,10);

// Filter valid papers (have paper.id)
let papers = allItems.filter(item => item.paper?.id);

if (papers.length === 0) {
  return [{ json: { date: dateStr, paper_id: 'none', title: 'No papers found for ' + dateStr, url: '#', upvotes: 0 } }];
}

// Sort by upvotes, take top 10
papers.sort((a,b) => (b.paper?.upvotes||0) - (a.paper?.upvotes||0));
return papers.slice(0, 10).map(p => ({
  json: {
    date: dateStr,
    paper_id: p.paper.id,
    title: p.paper.title || 'Untitled',
    url: 'https://huggingface.co/papers/' + p.paper.id,
    upvotes: p.paper.upvotes || 0
  }
}));
